import gc
from tinygrad.helpers import disable_gc

# Let's trace when __enter__ and __exit__ happen with detailed logging
class TracingDisableGC(disable_gc):
    def __enter__(self):
        print(f'TracingDisableGC.__enter__() called on instance {id(self)}')
        self._was_enabled = gc.isenabled()
        print(f'  Original GC state: {self._was_enabled}')
        if self._was_enabled: 
            gc.disable()
            print('  Disabled GC')
        print(f'  GC state after entering: {gc.isenabled()}')
        return self

    def __exit__(self, *exc):
        print(f'TracingDisableGC.__exit__() called on instance {id(self)}')
        print(f'  Was enabled: {self._was_enabled}')
        if self._was_enabled: 
            gc.enable()
            print('  Enabled GC')
        print(f'  GC state after exiting: {gc.isenabled()}')

@TracingDisableGC()
def recurse(depth: int):
    print(f'Inside recurse depth {depth} - GC enabled: {gc.isenabled()}')
    if depth > 0:
        recurse(depth - 1)
    print(f'Exiting recurse depth {depth} - GC enabled: {gc.isenabled()}')

was_enabled = gc.isenabled()
print(f'Original GC state: {was_enabled}')

try:
    recurse(2)
except Exception as e:
