class disable_gc(contextlib.ContextDecorator):
  # Using a class variable to track the depth, avoiding the instance state problem
  _depth: ClassVar[int] = 0
  _original_state: ClassVar[bool] = False

  def __enter__(self):
    if disable_gc._depth == 0:
      disable_gc._original_state = gc.isenabled()
    disable_gc._depth += 1
    if disable_gc._original_state:
      gc.disable()
    return self

  def __exit__(self, *exc):
    disable_gc._depth -= 1
    if disable_gc._depth == 0 and disable_gc._original_state:
      gc.enable()
